scwin.params = "";
scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");    // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = $c.date.addDate(scwin.vCurDate, -7);
//scwin.vQryStDt = $c.date.addDate(scwin.vCurDate, -10);
scwin.memJson = $c.data.getMemInfo();

scwin.hid_srchSelfTransCoCd="";
scwin.hid_srchSelfTransCoNm="";

scwin.onpageload = function() {

};

//var userClsCd = "<%=userClsCd%>";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = function () {  
    ica_srchFromDate.setValue(scwin.vCurDate);
	ica_srchToDate.setValue(scwin.vCurDate);
	ed_srchSelfTransCoCd.focus();

    //공통코드 적용()
    const codeOptions = [ 
        { grpCd : "SD060", compID : "acb_srchImpExpClsCd"} // 수출입 구분
        ,{ grpCd : "OP179", compID : "acb_srchRecptClsCd,gr_onReqInfo:admitClsCd"}   // 접수구분
    ];

    $c.data.setCommonCode(codeOptions);

	if(scwin.memJson.userClsCd != "01") {  //사용자 구분 : 05
		ed_srchSelfTransCoCd.setValue(scwin.memJson.clntNo);
		ed_srchSelfTransCoNm.setValue(scwin.memJson.clntNm);
		$c.gus.cfDisableObjects([udc_srchSelfTransCoCd]);
	} else {
		ed_srchSelfTransCoCd.setValue("");
		ed_srchSelfTransCoNm.setValue("");
		$c.gus.cfEnableObjects([udc_srchSelfTransCoCd]);
	}
};

scwin.onUdcCompleted = function() {
    scwin.f_OnLoad();
};

//-------------------------------------------------------------------------
// 검색조건 초기화 & 초기값 세팅
//-------------------------------------------------------------------------
scwin.f_SetInitCondVal = function (){
	ed_srchSelfTransCoCd.setValue("");
	ed_srchSelfTransCoNm.setValue("");
	scwin.hid_srchSelfTransCoCd = "";
	scwin.hid_srchSelfTransCoNm = "";

	acb_srchImpExpClsCd.setValue("");
	acb_srchRecptClsCd.setValue("");

    ica_srchFromDate.setValue(scwin.vCurDate);
	ica_srchToDate.setValue(scwin.vCurDate);
	ed_srchSelfTransCoCd.focus();
};

//-------------------------------------------------------------------------
// 코드 조회 팝업
//-------------------------------------------------------------------------
